        // Test data for classes (based on SeedData.cs)
        // IDs generated by database IDENTITY: Yoga=1, Spinning=2, CrossFit=3, Strech & Relax=4, Zumba=5, Pilates=6
        private const int classIdYoga = 1;
        private const string classNameYoga = "Yoga";
        private const string classTypeItemsYoga = "Yoga mat, Yoga block";
        private const string classDateYoga = "15/12/2025";
        private const string classTimeYoga = "18:00";
        private const string classPriceYoga = "11";
        
        private const int classIdPilates = 6;
        private const string classNamePilates = "Pilates";
        private const string classTypeItemsPilates = "Medicine Ball, Magic Ring";
        private const string classDatePilates = "20/12/2025";
        private const string classTimePilates = "15:30";
        private const string classPricePilates = "10";

        private const int classIdCrossFit = 3;
        private const string classNameCrossFit = "CrossFit";

        public UC_PlanClasses_UIT(ITestOutputHelper output) : base(output)
        {
            selectClassesForPlan_PO = new SelectClassesForPlan_PO(_driver, _output);
            createPlan_PO = new CreatePlan_PO(_driver, _output);
            detailPlan_PO = new DetailPlan_PO(_driver, _output);
        }

        private void Precondition_perform_login()
        {
            // Using a valid user from the database (dbo.AspNetUsers.data.sql)
            // Note: Update with actual credentials if needed
            Perform_login("alberto@uclm.es", "Pass123$");
        }

        private void InitialStepsForPlanClasses()
        {
            Precondition_perform_login();
            //we wait for the option of the menu to be visible
            selectClassesForPlan_PO.WaitForBeingVisible(By.Id("CreatePlan"));
            //we click on the menu
            _driver.FindElement(By.Id("CreatePlan")).Click();
        }

        // UC4-Esc2-1: No classes available for planning
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc2_1_NoClassesAvailable()
        {
            //Arrange
            InitialStepsForPlanClasses();
            
            //Act
            // Search with filters that won't return any results
            selectClassesForPlan_PO.SearchClasses("", "21/12/2025");

            //Assert
            Assert.True(selectClassesForPlan_PO.CheckMessageError("There are no classes available for the selected filters"));
        }

        // UC4-Esc3-1: Filter by Name - Y
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc3_1_FilterByName_Yoga()
        {
            //Arrange
            InitialStepsForPlanClasses();
            var expectedClasses = new List<string[]> { 
                new string[] { classNameYoga, classTypeItemsYoga, classDateYoga, classTimeYoga, classPriceYoga }
            };
            
            //Act
            selectClassesForPlan_PO.SearchClasses("Y", "");

            //Assert
            Assert.True(selectClassesForPlan_PO.CheckListOfClasses(expectedClasses));
        }

        // UC4-Esc3-2: Filter by Date - 20/12/2025 (Pilates)
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc3_2_FilterByDate_Pilates()
        {
            //Arrange
            InitialStepsForPlanClasses();
            var expectedClasses = new List<string[]> { 
                new string[] { classNamePilates, classTypeItemsPilates, classDatePilates, classTimePilates, classPricePilates }
            };
            
            //Act
