            //Assert
            Assert.True(selectClassesForPlan_PO.CheckListOfClasses(expectedClasses));
        }

        // UC4-Esc4-1: Date enrolment before today
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc4_1_DateBeforeToday()
        {
            //Arrange
            InitialStepsForPlanClasses();

            //Act
            selectClassesForPlan_PO.SearchClasses("", "10/12/2025");

            //Assert
            Assert.True(selectClassesForPlan_PO.CheckMessageError("The class date must be today or later"));
        }

        // UC4-Esc5-1: Modify plan cart - Add Yoga and Pilates, remove Yoga
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc5_1_ModifyPlanCart()
        {
            //Arrange
            InitialStepsForPlanClasses();
            
            //Act
            // Search and add Yoga and Pilates
            selectClassesForPlan_PO.SearchClasses("", "15/12/2025");
            selectClassesForPlan_PO.AddClassToPlanCart(classNameYoga);
            selectClassesForPlan_PO.AddClassToPlanCart(classNamePilates);
            
            // Remove Yoga
            selectClassesForPlan_PO.RemoveClassFromPlanCart(classIdYoga);

            //Assert
            // Verify that only Pilates remains in the cart
            // The Create Plan button should still be available since we have 1 class
            Assert.False(selectClassesForPlan_PO.CreatePlanNotAvailable());
        }

        // UC4-Esc6-1: Planning not available - Add and remove same class
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc6_1_PlanningNotAvailable()
        {
            //Arrange
            InitialStepsForPlanClasses();
            
            //Act
            // Search and add Yoga
            selectClassesForPlan_PO.SearchClasses("", "");
            selectClassesForPlan_PO.AddClassToPlanCart(classNameYoga);
            
            // Remove Yoga
            selectClassesForPlan_PO.RemoveClassFromPlanCart(classIdYoga);

            //Assert
            // Verify that the Create Plan button is disabled (not available)
            Assert.True(selectClassesForPlan_PO.CreatePlanNotAvailable());
        }

        // Helper method to navigate to CreatePlan page with a selected class
        private void InitialStepsForCreatePlan(string className)
        {
            InitialStepsForPlanClasses();
            
            // Search and add the specified class
            selectClassesForPlan_PO.SearchClasses(className, "");
            selectClassesForPlan_PO.AddClassToPlanCart(className);
            
            // Click on Create Plan button to navigate to CreatePlan page
            selectClassesForPlan_PO.WaitForBeingClickable(By.Id("createPlanButton"));
            _driver.FindElement(By.Id("createPlanButton")).Click();
        }

