        // UC4-Esc1-1: Successful plan creation with Credit Card
        [Fact]
        [Trait("LevelTesting", "Functional Testing")]
        public void UC4_Esc1_1_CreatePlanWithCreditCard()
        {
            //Arrange
            InitialStepsForCreatePlan(classNameYoga);
            string todayDate = DateTime.Now.ToString("dd/MM/yyyy");
            
            //Act
            createPlan_PO.FillPlanForm("alberto@uclm.es", "TestPlan", "8", "CreditCard");
            createPlan_PO.ClickSubmit();
            createPlan_PO.ConfirmDialog(); // Confirm dialog to create plan
            Thread.Sleep(3000); // Wait for navigation

            //Assert
            // Verify we are on DetailPlan page with correct data
            Assert.True(detailPlan_PO.CheckPlanDetails(
                "Alberto Bueno Baquero",
                "TestPlan",
                "N/A",
                "8",
                "None",
                "11 €",
                todayDate
            ));
            
            // Verify enrolled class
            Assert.True(detailPlan_PO.CheckEnrolledClass(
                classNameYoga,
                classTypeItemsYoga,
                classPriceYoga + " €",
                classDateYoga,
                classTimeYoga
            ));
        }

